mepc_setup:       
                  la x25, init
                  csrw 0x341, x25

custom_csr_setup: 
                  csrwi 0x7c0, 1

init_machine_mode:
                  li x25, 0x1bc018b2
                  csrw 0x300, x25 # MSTATUS
                  li x25, 0x73795fbb
                  csrw 0x304, x25 # MIE
                  li x10, 0x8ffffffc
                  li x25, 0x300
                  slli x25, x25, 8
                  addi x25, x25, 0x3
                  sw x25, 0(x10)
                  csrr x25, 0x300
                  sw x25, 0(x10)
                  li x10, 0x8ffffffc
                  li x25, 0x304
                  slli x25, x25, 8
                  addi x25, x25, 0x3
                  sw x25, 0(x10)
                  csrr x25, 0x304
                  sw x25, 0(x10)
                  mret
init:             
                  li x0, 0x0
                  li x1, 0x92ef9ac4
                  li x3, 0x80000000
                  li x4, 0x80000000
                  li x5, 0xe
                  li x6, 0xf1b29f3f
                  li x7, 0x0
