                  li x27, 0xf6358b8b
                  li x28, 0x0
                  li x29, 0x47c424ca
                  li x30, 0xc20d373d
                  li x31, 0x0
                  la x2, user_stack_end
                  li x10, 0x8ffffffc
                  li x25, 0x0
                  slli x25, x25, 8
                  addi x25, x25, 0x0
                  sw x25, 0(x10)
                  csrr x25, 0x300
                  csrr x10, 0x304
                  csrw 0x300, x25
                  csrw 0x304, x10
                  j main
test_done:        
                  li x10, 0x8ffffff8
                  li x25, 0x0
                  slli x25, x25, 8
                  addi x25, x25, 0x1
                  sw x25, 0(x10)
                  ecall

test_fail:        
                  li x10, 0x8ffffff8
                  li x25, 0x1
                  slli x25, x25, 8
                  addi x25, x25, 0x1
                  sw x25, 0(x10)
                  ecall

